    let mut m = Blake2sMac::<U32>::new_from_slice(key)?;
    for chunk in data {
        m.update(chunk);
    }
    let result: CtOutput<Blake2sMac<U32>> = m.finalize();
    Ok(result.into_bytes().into())
}

